import React, { useState, useEffect } from 'react';
import './Hero.css';

const Hero = () => {
  const [currentSlide, setCurrentSlide] = useState(0);

  const slides = [
    {
      id: 1,
      title: "Natural Healing",
      subtitle: "Ancient Wisdom",
      description: "Discover the power of nature's remedies for holistic wellness",
      buttonText: "Explore Remedies",
      discount: "25% OFF",
      backgroundImage: "https://images.unsplash.com/photo-1506905925346-21bda4d32df4?ixlib=rb-4.0.3&auto=format&fit=crop&w=1920&q=80"
    },
    {
      id: 2,
      title: "Herbal Medicine",
      subtitle: "Pure & Organic",
      description: "Traditional herbs carefully selected for their therapeutic properties",
      buttonText: "Shop Herbs",
      discount: "30% OFF",
      backgroundImage: "https://res.cloudinary.com/djksfayfu/image/upload/v1753290491/chelsea-shapouri-PwzCZVEw8vY-unsplash_kgerar.jpg"
    },
    {
      id: 3,
      title: "Wellness Journey",
      subtitle: "Transform Your Life",
      description: "Begin your path to natural health and vitality",
      buttonText: "Start Journey",
      discount: "Free Guide",
      backgroundImage: "https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?ixlib=rb-4.0.3&auto=format&fit=crop&w=1920&q=80"
    }
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentSlide((prevSlide) => (prevSlide + 1) % slides.length);
    }, 5000);

    return () => clearInterval(interval);
  }, [slides.length]);

  const goToSlide = (index) => {
    setCurrentSlide(index);
  };

  const nextSlide = () => {
    setCurrentSlide((prevSlide) => (prevSlide + 1) % slides.length);
  };

  const prevSlide = () => {
    setCurrentSlide((prevSlide) => (prevSlide - 1 + slides.length) % slides.length);
  };

  return (
    <section className="hero">
      <div className="hero-container">
        {slides.map((slide, index) => (
          <div
            key={slide.id}
            className={`hero-slide ${index === currentSlide ? 'active' : ''}`}
            style={{
              backgroundImage: `linear-gradient(rgba(0, 0, 0, 0.3), rgba(0, 0, 0, 0.3)), url(${slide.backgroundImage})`
            }}
          >
            <div className="hero-content">
              <div className="discount-badge">{slide.discount}</div>
              <h1 className="hero-title">{slide.title}</h1>
              <h2 className="hero-subtitle">{slide.subtitle}</h2>
              {slide.description && <p className="hero-description">{slide.description}</p>}
              <button className="hero-button">{slide.buttonText}</button>
            </div>
          </div>
        ))}

        {/* Navigation Arrows */}
        <button className="hero-arrow hero-arrow-left" onClick={prevSlide}>
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            <path d="M15 18L9 12L15 6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
        </button>
        <button className="hero-arrow hero-arrow-right" onClick={nextSlide}>
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            <path d="M9 18L15 12L9 6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
        </button>

        {/* Dots Navigation */}
        <div className="hero-dots">
          {slides.map((_, index) => (
            <button
              key={index}
              className={`hero-dot ${index === currentSlide ? 'active' : ''}`}
              onClick={() => goToSlide(index)}
            />
          ))}
        </div>
      </div>
    </section>
  );
};

export default Hero;
